THOUGHT: Now I can add a helper function before line 921 to check if a global has atomic operations. But actually, a simpler approach is to check within the `OptimizeGlobalAddressOfAllocation` function itself by examining the users.

Let me modify the function to skip the InitBool optimization if any user has atomic ordering:

```bash
# Add code to check for atomic operations before creating InitBool
sed -i '953i\
  // Check if any user of GV has atomic ordering\
  bool HasAtomicOperations = false;\
  SmallVector<Value *, 4> GusesCheck;\
  allUsesOfLoadAndStores(GV, GusesCheck);\
  for (auto *U : GusesCheck) {\
    if (StoreInst *SI = dyn_cast<StoreInst>(U)) {\
      if (SI->getOrdering() != AtomicOrdering::NotAtomic) {\
        HasAtomicOperations = true;\
        break;\
      }\
    } else if (LoadInst *LI = dyn_cast<LoadInst>(U)) {\
      if (LI->getOrdering() != AtomicOrdering::NotAtomic) {\
        HasAtomicOperations = true;\
        break;\
      }\
    }\
  }\
  \
  // If there are atomic operations, we cannot create atomic operations on i1\
  // because atomic memory access size must be byte-sized. Skip the InitBool optimization.\
  if (HasAtomicOperations) {\
    return NewGV;\
  }' /llvm-autofix-deps/llvm/llvm/llvm/lib/Transforms/IPO/GlobalOpt.cpp
```

